static VOID  _tx_win32_profile_accumulate(ULONG64 *ticks_total, ULONG *count_total, ULONG64 start_ticks)
{
ULONG64  end_ticks;

    end_ticks =  _tx_win32_profile_time_get();
    *ticks_total =  *ticks_total + (end_ticks - start_ticks);
    *count_total =  *count_total + 1UL;
}


static double  _tx_win32_profile_ticks_to_ms(ULONG64 ticks)
{
double  frequency;

    frequency =  (double) _tx_win32_profile_frequency.QuadPart;
    if (frequency == 0.0)
    {
        return(0.0);
    }

    return((((double) ticks) * 1000.0) / frequency);
}


