void  _tx_win32_critical_section_obtain(TX_WIN32_CRITICAL_SECTION *critical_section)
{
DWORD       thread_id;
LONG        previous_owner;
UINT        contention_count;
TX_THREAD   *current_thread;
UINT        core_scan;
#ifdef TX_WIN32_PROFILE_ENABLE
ULONG64     start_ticks;
#endif

    thread_id =  GetCurrentThreadId();

    if (critical_section -> tx_win32_critical_section_owner == thread_id)
    {
        critical_section -> tx_win32_critical_section_nested_count++;
    }
    else
    {
        /* If this is a ThreadX application thread, signal that it is about to
         * spin waiting for the critical section.  context_save checks this flag
         * before calling SuspendThread(): a thread that is merely blocked on the
         * spinlock does not need to be OS-suspended — it cannot execute protected
         * code anyway, and will proceed automatically once the CS is released.
         * The flag is cleared below once the CS has been acquired.
         *
         * Identify the calling thread by scanning _tx_win32_virtual_cores for a
         * matching OS thread ID.  As a fast path, check the TLS-cached virtual core
         * index first; fall back to a full scan only when the TLS value is stale
         * (e.g., after a type-1 scheduler hand-off moves the thread to a new core).
         * Worst case: the entry is momentarily absent and current_thread stays
         * TX_NULL, which simply skips the mutex_access optimisation this cycle. */
        current_thread =  TX_NULL;
        if (_tx_win32_threadx_thread != 0)
        {
            core_scan =  _tx_win32_current_virtual_core;
            if ((core_scan < TX_THREAD_SMP_MAX_CORES) &&
                (_tx_win32_virtual_cores[core_scan].tx_thread_smp_core_mapping_thread_id == thread_id))
            {
                current_thread =  _tx_win32_virtual_cores[core_scan].tx_thread_smp_core_mapping_thread;
            }
            else
            {
                for (core_scan = 0U; core_scan < TX_THREAD_SMP_MAX_CORES; core_scan++)
                {
                    if (_tx_win32_virtual_cores[core_scan].tx_thread_smp_core_mapping_thread_id == thread_id)
                    {
                        current_thread =  _tx_win32_virtual_cores[core_scan].tx_thread_smp_core_mapping_thread;
                        break;
                    }
                }
            }
            if (current_thread != TX_NULL)
            {
                current_thread -> tx_thread_win32_mutex_access =  TX_TRUE;
            }
        }

        contention_count =  0U;
#ifdef TX_WIN32_PROFILE_ENABLE
        start_ticks =  _tx_win32_profile_time_get();
#endif
        do
        {
            previous_owner =  InterlockedCompareExchange((LONG *) &(critical_section -> tx_win32_critical_section_owner), (LONG) thread_id, 0L);

            if (previous_owner != 0L)
            {
#ifdef TX_WIN32_PROFILE_ENABLE
                _tx_win32_profile.tx_win32_profile_critical_section_spin_count++;
#endif
                contention_count++;
                if (contention_count < TX_WIN32_CONTENTION_PAUSE_COUNT)
                {
                    YieldProcessor();
                }
                else
                {
                    contention_count =  0U;
                    _tx_win32_thread_yield();
                }
            }
        } while (previous_owner != 0L);

#ifdef TX_WIN32_PROFILE_ENABLE
        if (critical_section -> tx_win32_critical_section_owner == thread_id)
        {
            _tx_win32_profile.tx_win32_profile_critical_section_spin_ticks =
                _tx_win32_profile.tx_win32_profile_critical_section_spin_ticks +
                (_tx_win32_profile_time_get() - start_ticks);
        }
#endif
        /* CS acquired; clear the spinning flag so the next timer ISR will see
         * the thread as normally running.  The thread is now inside the CS body
         * and the ISR cannot reach context_save until we release the CS. */
        if (current_thread != TX_NULL)
        {
            current_thread -> tx_thread_win32_mutex_access =  TX_FALSE;
        }

        critical_section -> tx_win32_critical_section_nested_count =  1U;
    }
}


void  _tx_win32_critical_section_release(TX_WIN32_CRITICAL_SECTION *critical_section)
{
DWORD       thread_id;

    thread_id =  GetCurrentThreadId();

    if (critical_section -> tx_win32_critical_section_owner == thread_id)
    {
        if (critical_section -> tx_win32_critical_section_nested_count != 0U)
        {
            critical_section -> tx_win32_critical_section_nested_count--;

            if (critical_section -> tx_win32_critical_section_nested_count == 0U)
            {
                InterlockedExchange((LONG *) &(critical_section -> tx_win32_critical_section_owner), 0L);
            }
        }
    }
    else
    {
        _tx_win32_system_error++;
    }
}


void  _tx_win32_critical_section_release_all(TX_WIN32_CRITICAL_SECTION *critical_section)
{
DWORD       thread_id;
    
    thread_id =  GetCurrentThreadId();

    if (critical_section -> tx_win32_critical_section_owner == thread_id)
    {
        if (critical_section -> tx_win32_critical_section_nested_count != 0U)
        {
            critical_section -> tx_win32_critical_section_nested_count =  0U;
            InterlockedExchange((LONG *) &(critical_section -> tx_win32_critical_section_owner), 0L);
        }
    }
    else
    {
        _tx_win32_system_error++;
    }
}


UINT  _tx_win32_smp_current_core_get(void)
{
UINT    core;
DWORD   thread_id;
UINT    critical_section_owned;

    thread_id =  GetCurrentThreadId();
    critical_section_owned =  (UINT) (_tx_win32_critical_section.tx_win32_critical_section_owner == thread_id);

    if (critical_section_owned == TX_FALSE)
    {
        _tx_win32_critical_section_obtain(&_tx_win32_critical_section);
    }

    if (_tx_win32_threadx_thread != 0)
    {
        core =  _tx_win32_smp_thread_core_get(thread_id);

        if (core == TX_THREAD_SMP_MAX_CORES)
        {
            core =  _tx_win32_current_virtual_core;
        }
        else
        {
            _tx_win32_current_virtual_core =  core;
        }
    }
    else
    {
        core =  _tx_win32_smp_current_core_get_internal(thread_id);
        if (core == TX_THREAD_SMP_MAX_CORES)
        {
            core =  0U;
        }
    }

    if (critical_section_owned == TX_FALSE)
    {
        _tx_win32_critical_section_release(&_tx_win32_critical_section);
    }

    return(core);
}


static UINT  _tx_win32_smp_thread_core_get(DWORD thread_id)
{
UINT        core;
UINT        i;
TX_THREAD   *thread_ptr;

    core =  TX_THREAD_SMP_MAX_CORES;

    for (i = 0U; i < TX_THREAD_SMP_MAX_CORES; i++)
    {
        if (_tx_win32_virtual_cores[i].tx_thread_smp_core_mapping_thread_id == thread_id)
        {
            core =  i;
            break;
        }
    }

    if (core == TX_THREAD_SMP_MAX_CORES)
    {
        for (i = 0U; i < TX_THREAD_SMP_MAX_CORES; i++)
        {
            thread_ptr =  _tx_thread_current_ptr[i];
            if ((thread_ptr != TX_NULL) && (thread_ptr -> tx_thread_win32_thread_id == thread_id))
            {
                core =  i;
                break;
            }
        }
    }

    return(core);
}


static UINT  _tx_win32_smp_current_core_get_internal(DWORD thread_id)
{
UINT    core;
UINT    i;
TX_THREAD *thread_ptr;

    core =  _tx_win32_smp_thread_core_get(thread_id);

    if (core == TX_THREAD_SMP_MAX_CORES)
    {
        for (i = 0U; i < TX_THREAD_SMP_MAX_CORES; i++)
        {
            thread_ptr =  _tx_thread_execute_ptr[i];
            if ((thread_ptr != TX_NULL) && (thread_ptr -> tx_thread_win32_thread_id == thread_id))
            {
                core =  i;
                break;
            }
        }
    }

    return(core);
}


void  _tx_win32_thread_suspend(HANDLE thread_handle)
{
#ifdef TX_WIN32_PROFILE_ENABLE
ULONG64  start_ticks;

    start_ticks =  _tx_win32_profile_time_get();
#endif
    if (SuspendThread(thread_handle) == (DWORD) -1)
    {
        _tx_win32_system_error++;
        while (1)
        {
        }
    }
#ifdef TX_WIN32_PROFILE_ENABLE
    _tx_win32_profile_accumulate(&_tx_win32_profile.tx_win32_profile_suspend_ticks,
                                 &_tx_win32_profile.tx_win32_profile_suspend_count,
                                 start_ticks);
#endif
}


void  _tx_win32_thread_resume(HANDLE thread_handle)
{
    DWORD suspend_count;
#ifdef TX_WIN32_PROFILE_ENABLE
ULONG64  start_ticks;

    start_ticks =  _tx_win32_profile_time_get();
#endif

    do
    {
        suspend_count =  ResumeThread(thread_handle);
        if (suspend_count == (DWORD) -1)
        {
            _tx_win32_system_error++;
            while (1)
            {
            }
        }
    } while (suspend_count > 1U);
#ifdef TX_WIN32_PROFILE_ENABLE
    _tx_win32_profile_accumulate(&_tx_win32_profile.tx_win32_profile_resume_ticks,
                                 &_tx_win32_profile.tx_win32_profile_resume_count,
                                 start_ticks);
#endif
}


void  _tx_win32_thread_sleep(ULONG milliseconds)
{
    if (milliseconds == 0U)
    {
        milliseconds =  1U;
    }

    Sleep((DWORD) milliseconds);
}


void  _tx_win32_thread_yield(VOID)
{
#ifdef TX_WIN32_PROFILE_ENABLE
ULONG64  start_ticks;

    start_ticks =  _tx_win32_profile_time_get();
#endif

    if (SwitchToThread() == 0)
    {
        Sleep(0);
    }

#ifdef TX_WIN32_PROFILE_ENABLE
    _tx_win32_profile_accumulate(&_tx_win32_profile.tx_win32_profile_yield_ticks,
                                 &_tx_win32_profile.tx_win32_profile_yield_count,
                                 start_ticks);
#endif
}


void  _tx_win32_semaphore_reset(HANDLE semaphore_handle)
{
#ifdef TX_WIN32_PROFILE_ENABLE
ULONG64  start_ticks;

    start_ticks =  _tx_win32_profile_time_get();
#endif

    while (WaitForSingleObject(semaphore_handle, 0) == WAIT_OBJECT_0)
    {
#ifdef TX_WIN32_PROFILE_ENABLE
        _tx_win32_profile.tx_win32_profile_semaphore_reset_loops++;
#endif
    }

#ifdef TX_WIN32_PROFILE_ENABLE
    _tx_win32_profile_accumulate(&_tx_win32_profile.tx_win32_profile_semaphore_reset_ticks,
                                 &_tx_win32_profile.tx_win32_profile_semaphore_reset_count,
                                 start_ticks);
#endif
}


LONG  _tx_win32_thread_start_sequence_get(TX_THREAD *thread_ptr)
{
#if (TX_WIN32_USE_ADDRESS_WAIT != 0)
    return(thread_ptr -> tx_thread_win32_start_sequence);
#else
    TX_PARAMETER_NOT_USED(thread_ptr);
    return(0L);
#endif
}


void  _tx_win32_thread_run_signal(TX_THREAD *thread_ptr)
{
#if (TX_WIN32_USE_ADDRESS_WAIT != 0)
    (void) InterlockedIncrement(&(thread_ptr -> tx_thread_win32_run_sequence));
    WakeByAddressSingle(&(thread_ptr -> tx_thread_win32_run_sequence));
#else
    ReleaseSemaphore(thread_ptr -> tx_thread_win32_thread_run_semaphore, 1, NULL);
#endif
}


DWORD  _tx_win32_wait_for_thread_run(TX_THREAD *thread_ptr)
{
DWORD   wait_status;
#if (TX_WIN32_USE_ADDRESS_WAIT != 0)
LONG    observed_sequence;
LONG    current_sequence;
#endif
#ifdef TX_WIN32_PROFILE_ENABLE
ULONG64 start_ticks;

    start_ticks =  _tx_win32_profile_time_get();
#endif

#if (TX_WIN32_USE_ADDRESS_WAIT != 0)
    wait_status =        WAIT_OBJECT_0;
    observed_sequence =  thread_ptr -> tx_thread_win32_run_sequence_seen;
    current_sequence =   thread_ptr -> tx_thread_win32_run_sequence;

    while (current_sequence == observed_sequence)
    {
        if (WaitOnAddress(&(thread_ptr -> tx_thread_win32_run_sequence),
                          &observed_sequence,
                          sizeof(thread_ptr -> tx_thread_win32_run_sequence),
                          INFINITE) == 0)
        {
            _tx_win32_system_error++;
            wait_status =  WAIT_FAILED;
            break;
        }

        current_sequence =  thread_ptr -> tx_thread_win32_run_sequence;
    }

    if (wait_status == WAIT_OBJECT_0)
    {
        thread_ptr -> tx_thread_win32_run_sequence_seen =  current_sequence;
    }
#else
    wait_status =  WaitForSingleObject(thread_ptr -> tx_thread_win32_thread_run_semaphore, INFINITE);
#endif

#ifdef TX_WIN32_PROFILE_ENABLE
    _tx_win32_profile_accumulate(&_tx_win32_profile.tx_win32_profile_thread_run_wait_ticks,
                                 &_tx_win32_profile.tx_win32_profile_thread_run_wait_count,
                                 start_ticks);
#endif

    return(wait_status);
}


void  _tx_win32_thread_start_ack_signal(TX_THREAD *thread_ptr)
{
#if (TX_WIN32_USE_ADDRESS_WAIT != 0)
    (void) InterlockedIncrement(&(thread_ptr -> tx_thread_win32_start_sequence));
    WakeByAddressSingle(&(thread_ptr -> tx_thread_win32_start_sequence));
#else
    ReleaseSemaphore(thread_ptr -> tx_thread_win32_thread_start_semaphore, 1, NULL);
#endif
}


DWORD  _tx_win32_wait_for_scheduler_event(VOID)
{
DWORD   wait_status;
#ifdef TX_WIN32_PROFILE_ENABLE
ULONG64 start_ticks;

    start_ticks =  _tx_win32_profile_time_get();
#endif

    /* Use a 2 ms timeout (matching the Linux SMP port's sem_timedwait interval) so that
     * a missed SetEvent() does not stall the scheduler indefinitely and so that the
     * timer-tick phase varies slightly between iterations, preventing a systematic
     * resonance where the ISR always fires outside the _tx_thread_preempt_disable
     * window (which would make tests like threadx_thread_wait_abort_and_isr_test
     * take an unreasonably long time to complete). */
    wait_status =  WaitForSingleObject(_tx_win32_scheduler_event, 2U);

#ifdef TX_WIN32_PROFILE_ENABLE
    _tx_win32_profile_accumulate(&_tx_win32_profile.tx_win32_profile_scheduler_wait_ticks,
                                 &_tx_win32_profile.tx_win32_profile_scheduler_wait_count,
                                 start_ticks);
#endif

    return(wait_status);
}


